import json
import re

business_data = locals()['var_function-call-16557504328339835093']['results']

wifi_businesses = []
for biz in business_data:
    if biz['attributes'] and 'WiFi' in biz['attributes']:
        wifi_status = biz['attributes']['WiFi']
        if wifi_status and wifi_status.lower() not in ["u'no'", "'no'"]:
            description = biz.get('description', '')
            state_match = re.search(r'in ([A-Z]{2}),', description)
            if state_match:
                state = state_match.group(1)
                wifi_businesses.append({
                    'business_id': biz['business_id'],
                    'state': state
                })

print('__RESULT__:')
print(json.dumps(wifi_businesses))

